mapper.select:
SELECT COUNT(1)
FROM t_order
WHERE task_id = #{taskId}
  AND helper_id = #{helperId}
  AND is_deleted = false

SELECT o.id AS orderId, t.id AS taskId, t.title AS taskTitle, AS taskCategory, AS taskStatus, t.location AS taskLocation, t.reward, AS status, EXISTS ( SELECT 1 FROM t_review r WHERE r.order_id = o.id AND r.reviewer_id = #{userId} ) AS currentUserReviewed, t.team_total_members AS teamTotalMembers, t.team_current_members AS teamCurrentMembers, poster.id AS posterId, poster.nickname AS posterName, poster.avatar_url AS posterAvatarUrl, helper.id AS helperId, helper.nickname AS helperName, helper.avatar_url AS helperAvatarUrl, o.create_time AS createdAt, o.update_time AS updatedAt FROM t_order o JOIN t_task t ON t.id = o.task_id AND t.is_deleted = false JOIN u_user poster ON poster.id = o.poster_id AND poster.is_deleted = false JOIN u_user helper ON helper.id = o.helper_id AND helper.is_deleted = false WHERE o.is_deleted = false
AND o.poster_id = #{userId}
AND o.helper_id = #{userId}
AND (o.poster_id = #{userId} OR o.helper_id = #{userId})
ORDER BY o.create_time DESC OFFSET #{offset} LIMIT #{size}

SELECT COUNT(1) FROM t_order o JOIN t_task t ON t.id = o.task_id AND t.is_deleted = false JOIN u_user poster ON poster.id = o.poster_id AND poster.is_deleted = false JOIN u_user helper ON helper.id = o.helper_id AND helper.is_deleted = false WHERE o.is_deleted = false
AND o.poster_id = #{userId}
AND o.helper_id = #{userId}
AND (o.poster_id = #{userId} OR o.helper_id = #{userId})

